'use server';

import { suggestSimulationParameters } from '@/ai/flows/suggest-simulation-parameters';
import type { SimulationData } from '@/components/app-layout';
import { promises as fs } from 'fs';
import path from 'path';

// Mock function to simulate a backend process
const runMockSimulation = async (
  files: File[],
  params: Record<string, any>
): Promise<SimulationData> => {
  console.log('Running simulation with:');
  console.log('Files:', files.map(f => f.name));
  console.log('Params:', params);

  // Simulate network delay and processing time
  await new Promise(resolve => setTimeout(resolve, 3000));

  // Generate mock data
  const totalZones = Math.floor(Math.random() * 10) + 5;
  const activeBikes = Math.floor(Math.random() * 500) + 100;
  const avgTripDuration = Math.floor(Math.random() * 30) + 10;
  const issuesDetected = Math.floor(Math.random() * 5);

  const chartData = Array.from({ length: 7 }, (_, i) => ({
    name: `Zone ${i + 1}`,
    bikes: Math.floor(Math.random() * 100) + 10,
  }));

  const csvData = [
    ['zone_id', 'active_bikes', 'avg_trip_duration_mins'],
    ...chartData.map((d, i) => [i + 1, d.bikes, Math.floor(Math.random() * 15) + 5]),
  ]
    .map(e => e.join(','))
    .join('\n');

  return {
    zoneSummary: {
      totalZones,
      activeBikes,
      avgTripDuration,
      issuesDetected,
    },
    chartData,
    mapUrl: 'https://picsum.photos/seed/map1/1200/800',
    heatmapUrl: 'https://picsum.photos/seed/map2/1200/800',
    csvData,
  };
};

export async function runSimulationAction(_: any, formData: FormData) {
  try {
    const files = formData.getAll('files') as File[];
    if (!files || files.length === 0) return { error: 'No files uploaded' };

    const uploadDir = path.join(process.cwd(), 'uploads');
    await fs.mkdir(uploadDir, { recursive: true });

    const savedFiles: string[] = [];

    for (const file of files) {
      const bytes = await file.arrayBuffer();
      const buffer = Buffer.from(bytes);
      const filePath = path.join(uploadDir, file.name);
      await fs.writeFile(filePath, buffer);
      savedFiles.push(filePath);
    }

    // ✅ Run mock simulation and return SimulationData
    const simulationResult = await runMockSimulation(files, {});

    return { data: simulationResult, error: null };
  } catch (err: any) {
    return { error: err.message || 'Unknown error while saving files' };
  }
}

export async function getAiSuggestionsAction(fileNames: string[]) {
  if (fileNames.length === 0) {
    return {
      data: null,
      error: 'Please upload at least one file to get AI suggestions.',
    };
  }

  try {
    const result = await suggestSimulationParameters({ uploadedFiles: fileNames });
    return { data: result, error: null };
  } catch (error) {
    console.error(error);
    return { data: null, error: 'Failed to get AI suggestions.' };
  }
}
